def word_dictionary_ops(operations):
    class TrieNode:
        __slots__ = ("children", "is_word")

        def __init__(self):
            self.children = {}
            self.is_word = False

    class WordDictionary:
        def __init__(self):
            self.root = TrieNode()

        def addWord(self, word):
            node = self.root
            for ch in word:
                if ch not in node.children:
                    node.children[ch] = TrieNode()
                node = node.children[ch]
            node.is_word = True

        def search(self, word):
            def dfs(node, i):
                if i == len(word):
                    return node.is_word
                ch = word[i]
                if ch == ".":
                    return any(dfs(child, i + 1) for child in node.children.values())
                child = node.children.get(ch)
                return child is not None and dfs(child, i + 1)

            return dfs(self.root, 0)

    results = []
    wd = None
    for op in operations:
        method, args = op[0], op[1:]
        if method == "WordDictionary":
            wd = WordDictionary()
            results.append(None)
        elif method == "addWord":
            wd.addWord(*args)
            results.append(None)
        elif method == "search":
            results.append(wd.search(*args))
    return results
